+test('TemporalTracker - Prune versions', async () => {
+  const tracker = new TemporalTracker();
+
+  // Create many versions
+  for (let i = 0; i < 10; i++) {
+    tracker.trackChange({
+      type: ChangeType.ADDITION,
+      path: `node${i}`,
+      before: null,
+      after: `value${i}`,
+      timestamp: Date.now()
+    });
+
+    await tracker.createVersion({
+      description: `V${i}`,
+      tags: i < 2 ? ['important'] : []
